const COMPANION_MSGS = ["Scroll down — there's so much to explore!","Every expert was once a beginner. Keep going!","Try clicking on a learning path that excites you.","Your potential is limitless. Seriously.","Click me to chat! I'm always here for you.","Consistency beats intensity. Small steps, big results.","Try the Study Timer for focused learning sessions!","Check out the Knowledge Map — it's mesmerizing."];

const state = { name: '', xp: 0, level: 1, streak: 0, lastVisit: null, pathsVisited: new Set(), lessonsRead: new Set(), quizzesPassed: new Set(), perfectQuizzes: 0, chatCount: 0, bookmarks: new Set(), timerSessions: 0, certificates: 0, pathsCompleted: 0, unlockedAchievements: new Set(), quizResults: {}, nameSet: false };
let chatOpen = false, companionIdx = 0, companionInterval = null, voiceEnabled = false;
let currentTestimonial = 0;
let timerMode = 25, timerSeconds = 25*60, timerRunning = false, timerInterval = null, timerSessionsCount = 0;

function loadState(){ try{ const s=localStorage.getItem('lumina_state'); if(s){ const p=JSON.parse(s); Object.assign(state,p); state.pathsVisited=new Set(p.pathsVisited||[]); state.lessonsRead=new Set(p.lessonsRead||[]); state.quizzesPassed=new Set(p.quizzesPassed||[]); state.bookmarks=new Set(p.bookmarks||[]); state.unlockedAchievements=new Set(p.unlockedAchievements||[]); } const t=new Date().toDateString(); if(state.lastVisit){ const l=new Date(state.lastVisit); const d=Math.floor((new Date(t)-l)/(1000*60*60*24)); if(d>1)state.streak=0; if(d>=1)state.streak++; } else { state.streak=1; } state.lastVisit=t; saveState(); }catch(e){} }
function saveState(){ try{ const s={...state}; s.pathsVisited=[...state.pathsVisited]; s.lessonsRead=[...state.lessonsRead]; s.quizzesPassed=[...state.quizzesPassed]; s.bookmarks=[...state.bookmarks]; s.unlockedAchievements=[...state.unlockedAchievements]; localStorage.setItem('lumina_state',JSON.stringify(s)); }catch(e){} }

function showToast(msg){ const t=document.getElementById('toast'); t.innerHTML=msg; t.classList.add('show'); setTimeout(()=>t.classList.remove('show'),4000); }
function speak(text){ if(!voiceEnabled||!('speechSynthesis' in window))return; window.speechSynthesis.cancel(); const u=new SpeechSynthesisUtterance(text); u.rate=1;u.pitch=1.1;u.volume=0.8; const v=window.speechSynthesis.getVoices().find(v=>v.name.includes('Google')&&v.lang.startsWith('en')); if(v)u.voice=v; window.speechSynthesis.speak(u); }

function addXP(amount){ state.xp+=amount; const maxXP=500; const oldLevel=state.level; state.level=Math.floor(state.xp/maxXP)+1; document.getElementById('xpBar').style.setProperty('--xp-width', ((state.xp%maxXP)/maxXP*100)+'%'); document.getElementById('xpDisplay').textContent=`${state.xp%maxXP} / ${maxXP} XP`; document.getElementById('userLevel').textContent=state.level; if(state.level>oldLevel)celebrateLevelUp(state.level); checkAchievements(); saveState(); }

function openModal(html){ const m=document.getElementById('mainModal'); document.getElementById('mainModalContent').innerHTML=html; m.classList.add('open'); }
function closeModal(){ document.getElementById('mainModal').classList.remove('open'); }
document.getElementById('mainModal').addEventListener('click',e=>{ if(e.target===document.getElementById('mainModal'))closeModal(); });

function celebrateLevelUp(level){ const o=document.getElementById('celebrationOverlay'); o.classList.add('active'); o.innerHTML=''; const colors=['#00f5d4','#fee440','#f15bb5','#06d6a0','#ff6b6b','#a78bfa']; for(let i=0;i<50;i++){ const c=document.createElement('div'); c.className='confetti-piece'; c.style.cssText=`--left:${Math.random()*100}%;--bg:${colors[Math.floor(Math.random()*colors.length)]};--delay:${Math.random()*2}s;--dur:${2+Math.random()*2}s;--w:${6+Math.random()*8}px;--h:${6+Math.random()*8}px;--br:${Math.random()>.5?'50%':'2px'}`; o.appendChild(c); } showToast(`<i class="fas fa-arrow-up text-secondary mr-2"></i>LEVEL UP! You're now Level ${level}!`); speak(`Congratulations! You've reached level ${level}!`); setTimeout(()=>o.classList.remove('active'),4000); }

function checkAchievements(){ ACHIEVEMENTS.forEach(a=>{ if(!state.unlockedAchievements.has(a.id)&&a.condition(state)){ state.unlockedAchievements.add(a.id); showToast(`<i class="fas fa-trophy text-secondary mr-2"></i>Achievement Unlocked: ${a.title}!`); if(voiceEnabled)speak(`Achievement unlocked: ${a.title}!`); renderAchievements(); } }); saveState(); }

window.addEventListener('load',()=>{ loadState(); setTimeout(()=>{ document.getElementById('preloader').classList.add('hidden'); if(state.name){ document.getElementById('nameModal').classList.remove('open'); document.getElementById('navGreeting').textContent=`Hi, ${state.name}`; document.getElementById('navGreeting').classList.remove('hidden'); startHeroTyping(); startCompanion(); addXP(10); state.nameSet=true; checkAchievements(); } },1800); });

document.getElementById('nameSubmit').addEventListener('click',submitName);
document.getElementById('nameInput').addEventListener('keydown',e=>{if(e.key==='Enter')submitName()});
function submitName(){ const inp=document.getElementById('nameInput'); const n=inp.value.trim(); if(!n){inp.classList.add('border-accent');setTimeout(()=>inp.classList.remove('border-accent'),1500);return} state.name=n; state.nameSet=true; saveState(); document.getElementById('nameModal').classList.remove('open'); document.getElementById('navGreeting').textContent=`Hi, ${n}`; document.getElementById('navGreeting').classList.remove('hidden'); speak(`Hey ${n}! Welcome to Lumina. Your learning journey starts now!`); showToast(`<i class="fas fa-rocket text-primary mr-2"></i>Welcome aboard, ${n}! +50 XP`); addXP(50); startHeroTyping(); startCompanion(); }

const canvas=document.getElementById('heroCanvas'); const ctx=canvas.getContext('2d'); let particles=[],mouseX=0,mouseY=0;
function resizeCanvas(){canvas.width=canvas.parentElement.offsetWidth;canvas.height=canvas.parentElement.offsetHeight}
resizeCanvas(); window.addEventListener('resize',resizeCanvas);
class Particle{ constructor(){this.x=Math.random()*canvas.width;this.y=Math.random()*canvas.height;this.vx=(Math.random()-.5)*.5;this.vy=(Math.random()-.5)*.5;this.radius=Math.random()*2+1;this.baseAlpha=Math.random()*.5+.2;this.alpha=this.baseAlpha} update(){ this.x+=this.vx;this.y+=this.vy; const dx=this.x-mouseX,dy=this.y-mouseY,dist=Math.sqrt(dx*dx+dy*dy); if(dist<200){this.alpha=this.baseAlpha+(1-dist/200)*.6;this.vx+=dx/dist*.02;this.vy+=dy/dist*.02}else{this.alpha+=(this.baseAlpha-this.alpha)*.05} const speed=Math.sqrt(this.vx*this.vx+this.vy*this.vy);if(speed>1.5){this.vx*=.98;this.vy*=.98} if(this.x<0)this.x=canvas.width;if(this.x>canvas.width)this.x=0;if(this.y<0)this.y=canvas.height;if(this.y>canvas.height)this.y=0; } draw(){ctx.beginPath();ctx.arc(this.x,this.y,Math.max(.5,this.radius),0,Math.PI*2);ctx.fillStyle=`rgba(0,245,212,${this.alpha})`;ctx.fill()} }
const pCount=Math.min(100,Math.floor((canvas.width*canvas.height)/12000)); for(let i=0;i<pCount;i++)particles.push(new Particle());
function drawConnections(){ for(let i=0;i<particles.length;i++)for(let j=i+1;j<particles.length;j++){ const dx=particles[i].x-particles[j].x,dy=particles[i].y-particles[j].y,dist=Math.sqrt(dx*dx+dy*dy); if(dist<150){ctx.beginPath();ctx.moveTo(particles[i].x,particles[i].y);ctx.lineTo(particles[j].x,particles[j].y);ctx.strokeStyle=`rgba(0,245,212,${(1-dist/150)*.15})`;ctx.lineWidth=.5;ctx.stroke()} } }
function animateCanvas(){ ctx.clearRect(0,0,canvas.width,canvas.height); particles.forEach(p=>{p.update();p.draw()}); drawConnections(); requestAnimationFrame(animateCanvas); }
animateCanvas();
document.getElementById('hero').addEventListener('mousemove',e=>{const r=canvas.getBoundingClientRect();mouseX=e.clientX-r.left;mouseY=e.clientY-r.top});
document.addEventListener('mousemove',e=>{const g=document.getElementById('mouseGlow');g.style.left=e.clientX+'px';g.style.top=e.clientY+'px'});

const heroTitles=['Where Curiosity','Meets Infinity'];let heroLineIndex=0,heroCharIndex=0,heroText='';
function startHeroTyping(){typeHeroLine()}
function typeHeroLine(){ if(heroLineIndex>=heroTitles.length){document.getElementById('heroCursor').classList.add('hidden');return} const line=heroTitles[heroLineIndex]; if(heroCharIndex<line.length){ heroText+=line[heroCharIndex]; document.getElementById('heroTitle').innerHTML=heroTitles[0]+'<br>'+heroText.substring(heroTitles[0].length); heroCharIndex++;setTimeout(typeHeroLine,60); }else{heroLineIndex++;heroCharIndex=0;setTimeout(typeHeroLine,300)} }

(function(){ const c=document.getElementById('heroTags'); HERO_TAGS.forEach(t=>{ const el=document.createElement('div'); el.className=`knowledge-tag pointer-events-auto theme-${t.colorName} theme-tag`; el.style.animationDelay=t.delay+'s'; el.textContent=t.text; if(t.top)el.style.top=t.top;if(t.bottom)el.style.bottom=t.bottom;if(t.left)el.style.left=t.left;if(t.right)el.style.right=t.right; el.addEventListener('click',()=>{showToast(`<i class="fas fa-search text-primary mr-2"></i>Exploring ${t.text} — +15 XP`);addXP(15)}); c.appendChild(el); }); })();

function renderPaths(){ const grid=document.getElementById('pathsGrid');grid.innerHTML=''; PATHS.forEach((p,i)=>{ const totalLessons=p.modules.reduce((a,m)=>a+m.lessons.length,0); const completedLessons=p.modules.reduce((a,m)=>a+m.lessons.filter(l=>state.lessonsRead.has(l.id)).length,0); const progress=totalLessons?Math.round(completedLessons/totalLessons*100):0; const card=document.createElement('div'); card.className=`tilt-card glass p-6 rounded-2xl relative overflow-hidden cursor-pointer reveal theme-${p.colorName} delay-${i*100}`; card.innerHTML=` <div class="glare"></div> <div class="flex items-center justify-between mb-4"> <div class="w-12 h-12 rounded-xl flex items-center justify-center theme-bg-15"><i class="fas ${p.icon} text-lg theme-text"></i></div> <span class="text-xs font-display font-bold px-3 py-1 rounded-full theme-tag">${p.tag}</span> </div> <h3 class="font-display font-bold text-white text-lg mb-2">${p.title}</h3> <p class="text-muted text-sm leading-relaxed mb-3">${p.desc}</p> <div class="w-full h-1.5 rounded-full bg-base mb-2 overflow-hidden"><div class="h-full rounded-full transition-all theme-bg-15" style="width:${progress}%"></div></div> <div class="flex items-center justify-between"> <span class="text-xs text-muted">${completedLessons}/${totalLessons} lessons &middot; ${p.learners} learners</span> <span class="text-xs font-display font-bold theme-text">Explore <i class="fas fa-arrow-right ml-1"></i></span> </div> <div class="absolute bottom-0 left-0 right-0 h-1 theme-gradient-bottom"></div>`; card.addEventListener('click',()=>openPathDetail(p)); grid.appendChild(card); }); }
renderPaths();

function openPathDetail(path){ state.pathsVisited.add(path.id); checkAchievements(); saveState(); const totalLessons=path.modules.reduce((a,m)=>a+m.lessons.length,0); const completedLessons=path.modules.reduce((a,m)=>a+m.lessons.filter(l=>state.lessonsRead.has(l.id)).length,0); const progress=totalLessons?Math.round(completedLessons/totalLessons*100):0; let modulesHtml=path.modules.map(m=>{ let lessonsHtml=m.lessons.map(l=>{ const read=state.lessonsRead.has(l.id); const quizDone=state.quizResults[l.id]; return `<div class="lesson-card glass p-4 rounded-xl flex items-center gap-4 ${read?'completed theme-teal':''}" data-lesson="${l.id}" data-path="${path.id}"> <div class="w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 ${read?'theme-bg-20':'bg-white/5'}"> ${read?'<i class="fas fa-check theme-text text-sm"></i>':'<i class="fas fa-play text-muted text-xs"></i>'} </div> <div class="flex-1 min-w-0"> <p class="font-display font-bold text-white text-sm truncate">${l.title}</p> <p class="text-muted text-xs">${read?'Completed':'Not started'}${quizDone?` &middot; Quiz: ${quizDone.correct}/${quizDone.total}`:''}</p> </div> <button class="bookmark-btn w-8 h-8 rounded-lg flex items-center justify-center transition-all ${state.bookmarks.has(l.id)?'text-secondary bg-secondary/10':'text-muted/40 hover:text-secondary hover:bg-secondary/5'}" data-bookmark="${l.id}" title="Bookmark"><i class="fas fa-bookmark text-xs"></i></button> </div>`; }).join(''); return `<div class="mb-6"><h4 class="font-display font-bold text-white text-sm mb-3 flex items-center gap-2"><i class="fas fa-layer-group text-xs theme-text"></i> ${m.title}</h4><div class="space-y-2">${lessonsHtml}</div></div>`; }).join(''); const canCert=progress===100; openModal(` <div class="p-6 md:p-8 theme-${path.colorName}"> <div class="flex items-center justify-between mb-6"> <div class="flex items-center gap-4"> <div class="w-14 h-14 rounded-xl flex items-center justify-center theme-bg-15"><i class="fas ${path.icon} text-2xl theme-text"></i></div> <div><h2 class="font-display font-bold text-white text-2xl">${path.title}</h2><p class="text-muted text-sm">${completedLessons}/${totalLessons} lessons completed</p></div> </div> <button onclick="closeModal()" class="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center text-muted hover:text-white transition-all"><i class="fas fa-times"></i></button> </div> <div class="w-full h-2 rounded-full bg-base mb-6 overflow-hidden"><div class="h-full rounded-full theme-bg-15" style="width:${progress}%"></div></div> ${modulesHtml} ${canCert?`<button id="generateCert" class="w-full py-3 rounded-xl font-display font-bold text-deep bg-primary hover:bg-primary/90 transition-all active:scale-95 mt-4"><i class="fas fa-certificate mr-2"></i>Generate Certificate</button>`:`<p class="text-center text-muted text-sm mt-4">Complete all lessons to unlock your certificate</p>`} </div>`); document.querySelectorAll('.lesson-card').forEach(card=>{ card.addEventListener('click',e=>{ if(e.target.closest('.bookmark-btn'))return; const lessonId=card.dataset.lesson; const pathId=card.dataset.path; const p=PATHS.find(p=>p.id===pathId); const lesson=p.modules.flatMap(m=>m.lessons).find(l=>l.id===lessonId); if(lesson)openLesson(lesson,path); }); }); document.querySelectorAll('.bookmark-btn').forEach(btn=>{ btn.addEventListener('click',e=>{ e.stopPropagation(); const lid=btn.dataset.bookmark; if(state.bookmarks.has(lid)){state.bookmarks.delete(lid);btn.classList.remove('text-secondary','bg-secondary/10');btn.classList.add('text-muted/40');showToast('Bookmark removed');} else{state.bookmarks.add(lid);btn.classList.add('text-secondary','bg-secondary/10');btn.classList.remove('text-muted/40');showToast('<i class="fas fa-bookmark text-secondary mr-2"></i>Bookmarked! +10 XP');addXP(10);} checkAchievements();saveState(); }); }); const certBtn=document.getElementById('generateCert'); if(certBtn)certBtn.addEventListener('click',()=>generateCertificate(path)); }

function openLesson(lesson,path){ state.lessonsRead.add(lesson.id); checkAchievements(); saveState(); let quizHtml=''; if(lesson.quiz&&lesson.quiz.length>0){ quizHtml=`<div class="mt-8 border-t border-white/10 pt-6"> <h3 class="font-display font-bold text-white text-lg mb-4"><i class="fas fa-question-circle text-primary mr-2"></i>Knowledge Check</h3> <div id="quizContainer"> ${lesson.quiz.map((q,qi)=>` <div class="mb-6" data-quiz-index="${qi}"> <p class="text-white font-medium mb-3">${qi+1}. ${q.q}</p> <div class="grid grid-cols-1 sm:grid-cols-2 gap-2"> ${q.opts.map((o,oi)=>`<div class="quiz-option glass px-4 py-3 rounded-xl text-sm" data-question="${qi}" data-option="${oi}">${o}</div>`).join('')} </div> </div> `).join('')} <button id="submitQuiz" class="px-6 py-3 rounded-xl font-display font-bold text-deep bg-primary hover:bg-primary/90 transition-all active:scale-95 text-sm mt-4">Check Answers</button> </div></div>`; } openModal(` <div class="p-6 md:p-8 theme-${path.colorName}"> <div class="flex items-center justify-between mb-6"> <div class="flex items-center gap-3"> <div class="w-10 h-10 rounded-xl flex items-center justify-center theme-bg-15"><i class="fas ${path.icon} theme-text"></i></div> <div><p class="text-muted text-xs">${path.title}</p><h2 class="font-display font-bold text-white text-xl">${lesson.title}</h2></div> </div> <button onclick="closeModal()" class="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center text-muted hover:text-white transition-all"><i class="fas fa-times"></i></button> </div> <div class="prose prose-invert max-w-none"><p class="text-white/90 leading-relaxed text-base">${lesson.content}</p></div> ${quizHtml} </div>`); const quizOpts={}; document.querySelectorAll('.quiz-option').forEach(opt=>{ opt.addEventListener('click',()=>{ const qi=parseInt(opt.dataset.question); document.querySelectorAll(`.quiz-option[data-question="${qi}"]`).forEach(o=>{o.classList.remove('bg-primary/10','border-primary/40')}); opt.classList.add('bg-primary/10','border-primary/40'); quizOpts[qi]=parseInt(opt.dataset.option); }); }); const submitBtn=document.getElementById('submitQuiz'); if(submitBtn){ submitBtn.addEventListener('click',()=>{ let correct=0; lesson.quiz.forEach((q,qi)=>{ const selected=quizOpts[qi]; document.querySelectorAll(`.quiz-option[data-question="${qi}"]`).forEach(o=>{ const oi=parseInt(o.dataset.option); o.classList.add('disabled'); if(oi===q.ans)o.classList.add('correct'); else if(oi===selected)o.classList.add('incorrect'); }); if(selected===q.ans)correct++; }); const total=lesson.quiz.length; state.quizResults[lesson.id]={correct,total}; if(correct===total)state.perfectQuizzes++; state.quizzesPassed.add(lesson.id); const xpEarned=correct*25+(correct===total?50:0); addXP(xpEarned); saveState(); submitBtn.disabled=true; submitBtn.textContent=`Score: ${correct}/${total} — +${xpEarned} XP`; submitBtn.className=correct===total?'px-6 py-3 rounded-xl font-display font-bold text-deep bg-primary text-sm mt-4 w-full':'px-6 py-3 rounded-xl font-display font-bold text-white bg-accent/20 text-sm mt-4 w-full'; if(correct===total){showToast(`<i class="fas fa-star text-secondary mr-2"></i>Perfect score! +${xpEarned} XP`);if(voiceEnabled)speak('Perfect score! Amazing work!');}else{showToast(`You got ${correct}/${total}. +${xpEarned} XP. Keep learning!`);if(voiceEnabled)speak(`You got ${correct} out of ${total}. Keep going!`);} const pathLessons=path.modules.flatMap(m=>m.lessons); if(pathLessons.every(l=>state.lessonsRead.has(l.id))){state.pathsCompleted++;checkAchievements();} checkAchievements(); }); } }

function generateCertificate(path){ const c=document.createElement('canvas'); c.width=1000;c.height=700; const cx=c.getContext('2d'); cx.fillStyle='#0c1222';cx.fillRect(0,0,1000,700); cx.strokeStyle='#00f5d4';cx.lineWidth=3;cx.strokeRect(30,30,940,640); cx.strokeStyle='rgba(0,245,212,.3)';cx.lineWidth=1;cx.strokeRect(40,40,920,620); cx.fillStyle='#00f5d4';cx.font='bold 16px "Space Grotesk", sans-serif';cx.textAlign='center';cx.fillText('LUMINA LEARNING PLATFORM',500,100); cx.fillStyle='#ffffff';cx.font='bold 40px "Space Grotesk", sans-serif';cx.fillText('Certificate of Completion',500,180); cx.beginPath();cx.moveTo(300,200);cx.lineTo(700,200);cx.strokeStyle='#00f5d4';cx.lineWidth=2;cx.stroke(); cx.fillStyle='#00f5d4';cx.font='bold 36px "Space Grotesk", sans-serif';cx.fillText(state.name||'Explorer',500,280); cx.fillStyle='#8892a8';cx.font='18px "DM Sans", sans-serif';cx.fillText('has successfully completed all lessons in',500,340); cx.fillStyle='#fee440';cx.font='bold 28px "Space Grotesk", sans-serif';cx.fillText(path.title,500,390); cx.fillStyle='#8892a8';cx.font='16px "DM Sans", sans-serif';cx.fillText(new Date().toLocaleDateString('en-US',{year:'numeric',month:'long',day:'numeric'}),500,460); cx.fillStyle='#f15bb5';cx.font='14px "Space Grotesk", sans-serif';cx.fillText(`${state.xp} XP Earned  •  Level ${state.level}`,500,510); cx.beginPath();cx.arc(500,590,35,0,Math.PI*2);cx.fillStyle='rgba(0,245,212,.1)';cx.fill();cx.strokeStyle='#00f5d4';cx.lineWidth=2;cx.stroke(); cx.fillStyle='#00f5d4';cx.font='bold 12px "Space Grotesk"';cx.fillText('LUMINA',500,588);cx.font='8px "DM Sans"';cx.fillText('VERIFIED',500,600); const link=document.createElement('a');link.download=`LUMINA-${path.title}-Certificate.png`;link.href=c.toDataURL();link.click(); state.certificates++;checkAchievements();saveState();showToast('<i class="fas fa-certificate text-primary mr-2"></i>Certificate downloaded! +100 XP');addXP(100); }

(function(){ const grid=document.getElementById('featuresGrid'); FEATURES.forEach((f,i)=>{ const card=document.createElement('div'); card.className=`glass p-6 rounded-2xl reveal delay-${i*100} group cursor-pointer theme-${f.colorName}`; card.innerHTML=` <div class="w-14 h-14 rounded-2xl flex items-center justify-center mb-5 transition-transform group-hover:scale-110 group-hover:rotate-3 theme-bg-15"><i class="fas ${f.icon} text-xl theme-text"></i></div> <h3 class="font-display font-bold text-white text-lg mb-2">${f.title}</h3> <p class="text-muted text-sm leading-relaxed">${f.desc}</p>`; card.addEventListener('click',()=>{ switch(f.action){ case 'chat':if(!chatOpen)toggleChat();break; case 'graph':document.getElementById('knowledgeGraph').scrollIntoView({behavior:'smooth'});break; case 'quests':document.getElementById('quests').scrollIntoView({behavior:'smooth'});break; case 'community':document.getElementById('community').scrollIntoView({behavior:'smooth'});break; case 'timer':document.getElementById('timer').scrollIntoView({behavior:'smooth'});break; case 'cert':showToast('<i class="fas fa-info-circle text-primary mr-2"></i>Complete a learning path to earn your certificate!');break; } }); grid.appendChild(card); }); })();

function initTilt(){ document.querySelectorAll('.tilt-card').forEach(card=>{ card.addEventListener('mousemove',e=>{ const r=card.getBoundingClientRect(),x=e.clientX-r.left,y=e.clientY-r.top; card.style.transform=`perspective(1000px) rotateX(${(y-r.height/2)/r.height*-8}deg) rotateY(${(x-r.width/2)/r.width*8}deg) scale(1.02)`; const g=card.querySelector('.glare');if(g)g.style.background=`radial-gradient(circle at ${x}px ${y}px,rgba(255,255,255,.12),transparent 60%)`; }); card.addEventListener('mouseleave',()=>{card.style.transform='perspective(1000px) rotateX(0) rotateY(0) scale(1)'}); }); }

(function(){ const grid=document.getElementById('skillGrid'); SKILLS.forEach((s,i)=>{ const node=document.createElement('div'); node.className=`skill-node flex flex-col items-center reveal delay-${i*80} theme-${s.colorName}`; node.innerHTML=` <div class="node-ring rounded-full"></div> <div class="w-16 h-16 rounded-full flex items-center justify-center mb-2 transition-all theme-bg-15 theme-border-40" style="border-width:2px"><i class="fab ${s.icon||'fas '+s.icon} text-lg theme-text"></i></div> <p class="font-display font-bold text-white text-xs text-center">${s.title}</p> <p class="text-muted text-xs mt-0.5">${s.xp}%</p>`; node.addEventListener('click',()=>{showToast(`<i class="fas fa-bolt text-primary mr-2"></i>${s.title} activated! +${Math.floor(s.xp/5)} XP`);addXP(Math.floor(s.xp/5))}); grid.appendChild(node); }); })();

function renderAchievements(){ const grid=document.getElementById('achievementsGrid');grid.innerHTML=''; ACHIEVEMENTS.forEach(a=>{ const unlocked=state.unlockedAchievements.has(a.id); const card=document.createElement('div'); card.className=`glass p-4 rounded-xl flex items-center gap-3 ${unlocked?'':'opacity-40'} theme-${a.colorName}`; card.innerHTML=` <div class="w-10 h-10 rounded-lg flex items-center justify-center flex-shrink-0 ${unlocked?'theme-bg-20':'bg-white/5'}"><i class="fas ${a.icon} ${unlocked?'theme-text':'text-gray-600'}"></i></div> <div class="min-w-0"><p class="font-display font-bold text-white text-xs truncate">${a.title}</p><p class="text-muted text-xs truncate">${unlocked?a.desc:'Locked'}</p></div>`; grid.appendChild(card); }); }
renderAchievements();

(function(){ const cvs=document.getElementById('knowledgeGraphCanvas'); const gctx=cvs.getContext('2d'); const W=800,H=500; const graphNodes=[ {id:'programming',label:'Programming',x:400,y:250,colorName:'teal',r:30}, {id:'python',label:'Python',x:220,y:150,colorName:'yellow',r:22}, {id:'javascript',label:'JavaScript',x:580,y:150,colorName:'pink',r:22}, {id:'data',label:'Data Science',x:180,y:350,colorName:'teal',r:24}, {id:'ai',label:'AI/ML',x:300,y:400,colorName:'purple',r:24}, {id:'design',label:'Design',x:600,y:350,colorName:'pink',r:24}, {id:'web',label:'Web Dev',x:680,y:230,colorName:'red',r:20}, {id:'mobile',label:'Mobile',x:720,y:330,colorName:'green',r:18}, {id:'stats',label:'Statistics',x:100,y:250,colorName:'yellow',r:18}, {id:'nlp',label:'NLP',x:350,y:450,colorName:'purple',r:18}, {id:'cv',label:'Computer Vision',x:200,y:450,colorName:'purple',r:18}, {id:'ux',label:'UX Research',x:650,y:430,colorName:'red',r:18}, {id:'ui',label:'UI Design',x:550,y:430,colorName:'pink',r:18}, {id:'database',label:'Databases',x:480,y:120,colorName:'green',r:18} ]; const colorMap = { teal:'#00f5d4', yellow:'#fee440', pink:'#f15bb5', red:'#ff6b6b', purple:'#a78bfa', green:'#06d6a0' }; const graphEdges=[['programming','python'],['programming','javascript'],['programming','web'],['python','data'],['python','ai'],['data','stats'],['data','ai'],['ai','nlp'],['ai','cv'],['javascript','web'],['web','mobile'],['design','ux'],['design','ui'],['javascript','design'],['programming','database'],['python','nlp'],['data','database']]; let dragNode=null,offsetX=0,offsetY=0,graphScale=1; function drawGraph(){ gctx.clearRect(0,0,W,H); gctx.save(); gctx.scale(graphScale,graphScale); graphEdges.forEach(([a,b])=>{ const na=graphNodes.find(n=>n.id===a),nb=graphNodes.find(n=>n.id===b); gctx.beginPath();gctx.moveTo(na.x,na.y);gctx.lineTo(nb.x,nb.y); gctx.strokeStyle='rgba(0,245,212,.12)';gctx.lineWidth=1.5;gctx.stroke(); }); graphNodes.forEach(n=>{ const c = colorMap[n.colorName]; const grad=gctx.createRadialGradient(n.x,n.y,0,n.x,n.y,n.r*2); grad.addColorStop(0,c+'30');grad.addColorStop(1,'transparent'); gctx.fillStyle=grad;gctx.beginPath();gctx.arc(n.x,n.y,n.r*2,0,Math.PI*2);gctx.fill(); gctx.beginPath();gctx.arc(n.x,n.y,n.r,0,Math.PI*2); gctx.fillStyle=c+'20';gctx.fill(); gctx.strokeStyle=c+'80';gctx.lineWidth=2;gctx.stroke(); gctx.fillStyle='#e2e8f0';gctx.font='bold 11px "Space Grotesk",sans-serif'; gctx.textAlign='center';gctx.textBaseline='middle'; gctx.fillText(n.label,n.x,n.y); }); gctx.restore(); } drawGraph(); function getGraphPos(e){ const rect=cvs.getBoundingClientRect(); const scaleX=W/rect.width,scaleY=H/rect.height; return{x:(e.clientX-rect.left)*scaleX/graphScale,y:(e.clientY-rect.top)*scaleY/graphScale}; } cvs.addEventListener('mousedown',e=>{ const pos=getGraphPos(e); for(const n of graphNodes){ const dx=pos.x-n.x,dy=pos.y-n.y; if(Math.sqrt(dx*dx+dy*dy)<n.r){dragNode=n;offsetX=dx;offsetY=dy;cvs.classList.add('grabbing');break} } }); cvs.addEventListener('mousemove',e=>{ if(!dragNode)return; const pos=getGraphPos(e); dragNode.x=pos.x-offsetX;dragNode.y=pos.y-offsetY; drawGraph(); }); cvs.addEventListener('mouseup',()=>{if(dragNode){cvs.classList.remove('grabbing');dragNode=null}}); cvs.addEventListener('mouseleave',()=>{if(dragNode){cvs.classList.remove('grabbing');dragNode=null}}); cvs.addEventListener('click',e=>{ if(dragNode)return; const pos=getGraphPos(e); for(const n of graphNodes){ const dx=pos.x-n.x,dy=pos.y-n.y; if(Math.sqrt(dx*dx+dy*dy)<n.r){ const related=graphEdges.filter(([a,b])=>a===n.id||b===n.id).map(([a,b])=>a===n.id?b:a); const relatedLabels=related.map(r=>graphNodes.find(gn=>gn.id===r)?.label).filter(Boolean); showToast(`<i class="fas fa-project-diagram mr-2 theme-text"></i>${n.label} connects to: ${relatedLabels.join(', ')} — +20 XP`); addXP(20); break; } } }); cvs.addEventListener('wheel',e=>{ e.preventDefault(); graphScale=Math.max(.5,Math.min(2,graphScale+(e.deltaY>0?-.05:.05))); drawGraph(); },{passive:false}); })();

(function(){ const display=document.getElementById('timerDisplay'); const circle=document.getElementById('timerCircle'); const circumference=2*Math.PI*100; circle.style.strokeDasharray=circumference; circle.style.strokeDashoffset=0; function updateTimerDisplay(){ const m=Math.floor(timerSeconds/60).toString().padStart(2,'0'); const s=(timerSeconds%60).toString().padStart(2,'0'); display.textContent=`${m}:${s}`; const totalSeconds=timerMode*60; const progress=(totalSeconds-timerSeconds)/totalSeconds; circle.style.strokeDashoffset=circumference*(1-progress); if(timerMode===25)circle.style.stroke='#00f5d4'; else if(timerMode===5)circle.style.stroke='#06d6a0'; else circle.style.stroke='#a78bfa'; } document.querySelectorAll('.tab-btn').forEach(btn=>{ btn.addEventListener('click',()=>{ document.querySelectorAll('.tab-btn').forEach(b=>{b.classList.remove('active');b.classList.add('text-muted');b.style.borderColor='rgba(255,255,255,.1)'}); btn.classList.add('active');btn.classList.remove('text-muted');btn.style.borderColor='rgba(0,245,212,.2)'; timerMode=parseInt(btn.dataset.timer); timerSeconds=timerMode*60; if(timerRunning){clearInterval(timerInterval);timerRunning=false;document.getElementById('timerStart').innerHTML='<i class="fas fa-play mr-2"></i>Start'} updateTimerDisplay(); }); }); document.getElementById('timerStart').addEventListener('click',()=>{ if(timerRunning){ clearInterval(timerInterval);timerRunning=false; document.getElementById('timerStart').innerHTML='<i class="fas fa-play mr-2"></i>Resume'; } else { timerRunning=true; document.getElementById('timerStart').innerHTML='<i class="fas fa-pause mr-2"></i>Pause'; timerInterval=setInterval(()=>{ timerSeconds--; updateTimerDisplay(); if(timerSeconds<=0){ clearInterval(timerInterval);timerRunning=false; document.getElementById('timerStart').innerHTML='<i class="fas fa-play mr-2"></i>Start'; timerSessionsCount++;state.timerSessions++; document.getElementById('timerSessions').textContent=timerSessionsCount; showToast('<i class="fas fa-bell text-primary mr-2"></i>Session complete! +50 XP'); addXP(50); if(voiceEnabled)speak('Session complete! Great focus.'); checkAchievements(); timerSeconds=timerMode*60; updateTimerDisplay(); } },1000); } }); document.getElementById('timerReset').addEventListener('click',()=>{ clearInterval(timerInterval);timerRunning=false; timerSeconds=timerMode*60; document.getElementById('timerStart').innerHTML='<i class="fas fa-play mr-2"></i>Start'; updateTimerDisplay(); }); updateTimerDisplay(); })();

(function(){ const track=document.getElementById('testimonialTrack'),dots=document.getElementById('testimonialDots'); TESTIMONIALS.forEach((t,i)=>{ const card=document.createElement('div');card.className='flex-shrink-0 w-full px-4'; card.innerHTML=`<div class="glass p-8 rounded-2xl max-w-2xl mx-auto text-center"><div class="w-16 h-16 rounded-full mx-auto mb-4 overflow-hidden border-2 border-primary/30"><img src="${t.avatar}" alt="${t.name}" class="w-full h-full object-cover" loading="lazy"></div><p class="text-white leading-relaxed mb-4 italic">"${t.text}"</p><p class="font-display font-bold text-primary text-sm">${t.name}</p><p class="text-muted text-xs">${t.role}</p></div>`; track.appendChild(card); const dot=document.createElement('button');dot.className=`w-2 h-2 rounded-full transition-all ${i===0?'bg-primary w-6':'bg-white/20'}`; dot.addEventListener('click',()=>goToTestimonial(i));dots.appendChild(dot); }); setInterval(()=>{goToTestimonial((currentTestimonial+1)%TESTIMONIALS.length)},5000); })();
function goToTestimonial(i){ currentTestimonial=i; document.getElementById('testimonialTrack').style.transform=`translateX(-${i*100}%)`; document.querySelectorAll('#testimonialDots button').forEach((d,j)=>{d.className=`h-2 rounded-full transition-all ${j===i?'bg-primary w-6':'bg-white/20 w-2'}`}); }

const counterObs=new IntersectionObserver(entries=>{ entries.forEach(e=>{if(e.isIntersecting){const t=parseInt(e.target.dataset.target);animCounter(e.target,t);counterObs.unobserve(e.target)}}); },{threshold:.5});
function animCounter(el,target){let cur=0;const inc=target/60;const t=setInterval(()=>{cur+=inc;if(cur>=target){cur=target;clearInterval(t)}el.textContent=target<100?Math.floor(cur):Math.floor(cur).toLocaleString()},25)}

const revealObs=new IntersectionObserver(entries=>{ entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add('visible');revealObs.unobserve(e.target)}}); },{threshold:.1,rootMargin:'0px 0px -40px 0px'});

